(* ============================================================ *)
(* PROG_TEST: 서보 단독 테스트 (이 프로그램만 단독 실행)         *)
(*                                                              *)
(* 조작:                                                        *)
(*   _00_IN00 (서보ON)  → 서보 전원                              *)
(*   _00_IN13 (리셋SW)  → 1회: 원점 / 다시: 360도 회전           *)
(*   _00_IN11 (EMO)     → 비상정지                               *)
(* ============================================================ *)

(* 입력 *)
bEmo := NOT _00_IN11;
rtButton(CLK := _00_IN13);

(* EMO → 즉시 정지 *)
IF bEmo THEN
    bHomeExec := FALSE;
    bMoveExec := FALSE;
    fbStop(Axis := _MC_AX[0], Execute := TRUE, Deceleration := 0);
    eStep := 0;
    RETURN;
END_IF;

(* 스텝 *)
CASE eStep OF

0: (* 대기 — 버튼 → 원점복귀 *)
    bHomeExec := FALSE;
    bMoveExec := FALSE;
    fbStop(Axis := _MC_AX[0], Execute := FALSE, Deceleration := 0);

    IF rtButton.Q AND _00_IN00 THEN
        bHomeExec := TRUE;
        eStep := 1;
    END_IF;

1: (* 원점복귀 중 *)
    fbHome(Axis := _MC_AX[0], Execute := bHomeExec);

    IF fbHome.Done THEN
        bHomeExec := FALSE;
        eStep := 2;
    ELSIF fbHome.Error THEN
        bHomeExec := FALSE;
        eStep := 0;
    END_IF;

2: (* 원점 완료 — 버튼 → 360도 회전 *)
    IF rtButton.Q THEN
        bMoveExec := TRUE;
        eStep := 3;
    END_IF;

3: (* 이동 중 *)
    fbMoveAbs(
        Axis         := _MC_AX[0],
        Execute      := bMoveExec,
        Position     := 36000.0,
        Velocity     := 10000.0,
        Acceleration := 0,
        Deceleration := 0,
        Direction    := 0
    );

    IF fbMoveAbs.Done THEN
        bMoveExec := FALSE;
        eStep := 4;
    ELSIF fbMoveAbs.Error THEN
        bMoveExec := FALSE;
        eStep := 0;
    END_IF;

4: (* 완료 — 버튼 → 다시 원점부터 *)
    IF rtButton.Q THEN
        bHomeExec := TRUE;
        eStep := 1;
    END_IF;

END_CASE;

