(* ============================================================ *)
(* PROG_TEST: 서보 단독 테스트 (이 프로그램만 단독 실행)         *)
(*                                                              *)
(* 조작:                                                        *)
(*   _00_IN00 (서보ON)  → 서보 전원                              *)
(*   _00_IN13 (리셋SW)  → 1회: 원점 / 다시: 360도 회전           *)
(*   _00_IN11 (EMO)     → 비상정지                               *)
(*                                                              *)
(* 위치결정모듈: BASE=0, SLOT=9, AXIS=0 (X축)                   *)
(* FB: APM_ORG(원점), APM_DST(위치이동), APM_STP(정지)          *)
(* ============================================================ *)

(* 입력 *)
bEmo := NOT _00_IN11;
rtButton(CLK := _00_IN13);

(* EMO → 즉시 정지 *)
IF bEmo THEN
    bOrgReq := FALSE;
    bDstReq := FALSE;
    bStpReq := TRUE;

    fbStp(REQ := bStpReq, BASE := 0, SLOT := 9, AXIS := 0,
          DEC_TIME := 0, DONE => bStpDone, STAT => wStpStat);

    eStep := 0;
    RETURN;
END_IF;

(* 스텝 *)
CASE eStep OF

0: (* 대기 — 버튼 → 원점복귀 *)
    bOrgReq := FALSE;
    bDstReq := FALSE;
    bStpReq := FALSE;

    IF rtButton.Q AND _00_IN00 THEN
        bOrgReq := TRUE;
        eStep := 1;
    END_IF;

1: (* 원점복귀 중 *)
    fbOrg(REQ := bOrgReq, BASE := 0, SLOT := 9, AXIS := 0,
          DONE => bOrgDone, STAT => wOrgStat);

    IF bOrgDone THEN
        bOrgReq := FALSE;
        eStep := 2;
    ELSIF wOrgStat <> 0 THEN
        bOrgReq := FALSE;
        eStep := 0;
    END_IF;

2: (* 원점 완료 — 버튼 → 360도 회전 *)
    IF rtButton.Q THEN
        bDstReq := TRUE;
        eStep := 3;
    END_IF;

3: (* 이동 중 — 36000펄스 = 360도 (100펄스/도 기준) *)
    fbDst(REQ := bDstReq, BASE := 0, SLOT := 9, AXIS := 0,
          ADDR := 36000, SPEED := 50000, DWELL := 0,
          MCODE := 0, POS_SPD := TRUE, ABS_INC := FALSE,
          TIME_SEL := 0, DONE => bDstDone, STAT => wDstStat);

    IF bDstDone THEN
        bDstReq := FALSE;
        eStep := 4;
    ELSIF wDstStat <> 0 THEN
        bDstReq := FALSE;
        eStep := 0;
    END_IF;

4: (* 완료 — 버튼 → 다시 원점부터 *)
    IF rtButton.Q THEN
        bOrgReq := TRUE;
        eStep := 1;
    END_IF;

END_CASE;

