(* 위치결정모듈: BASE=0, SLOT=9, AXIS=0 (X축)                   *)
(* ============================================================ *)

(* 리셋SW 수동 엣지 검출 → 서보ON 토글 *)
IF %IX0.0.11 AND NOT bResetPrev THEN
    bServoOn := NOT bServoOn;
END_IF;
bResetPrev := %IX0.0.11;

(* 동작SW 수동 엣지 검출 *)
bBtnEdge := %IX0.0.13 AND NOT bBtnPrev;
bBtnPrev := %IX0.0.13;

(* 서보ON 출력 *)
%QX0.0.5 := bServoOn;

(* 서보OFF면 스텝 초기화 *)
IF NOT bServoOn THEN
    eStep := 0;
    RETURN;
END_IF;

(* 스텝 *)
CASE eStep OF

0: (* 대기 — 동작SW → 원점복귀 *)
    bOrgReq := FALSE;
    bDstReq := FALSE;

    IF bBtnEdge THEN
        bOrgReq := TRUE;
        eStep := 1;
    END_IF;

1: (* 원점복귀 중 *)
    fbOrg(REQ := bOrgReq, BASE := 0, SLOT := 9, AXIS := 0,
          DONE => bOrgDone, STAT => wOrgStat);

    IF bOrgDone THEN
        bOrgReq := FALSE;
        eStep := 2;
    ELSIF wOrgStat <> 0 THEN
        bOrgReq := FALSE;
        eStep := 0;
    END_IF;

2: (* 원점 완료 — 동작SW → 30도 회전 (1틱) *)
    IF bBtnEdge THEN
        bDstReq := TRUE;
        eStep := 3;
    END_IF;

3: (* 이동 중 — 30도 = 30000 (기존 신진 기준) *)
    fbDst(REQ := bDstReq, BASE := 0, SLOT := 9, AXIS := 0,
          ADDR := 30000, SPEED := 50000, DWELL := 0,
          MCODE := 0, POS_SPD := TRUE, ABS_INC := FALSE,
          TIME_SEL := 0, DONE => bDstDone, STAT => wDstStat);

    IF bDstDone THEN
        bDstReq := FALSE;
        eStep := 4;
    ELSIF wDstStat <> 0 THEN
        bDstReq := FALSE;
        eStep := 0;
    END_IF;

4: (* 완료 — 동작SW → 다시 원점부터 *)
    IF bBtnEdge THEN
        bOrgReq := TRUE;
        eStep := 1;
    END_IF;

END_CASE;

