  1→using System;
  2→using System.IO;
  3→using System.Text;
  4→
  5→namespace AssembleMonitor.Features.Communication;
  6→
  7→/// <summary>
  8→/// LS XGT FEnet 프로토콜 패킷 생성/파싱
  9→/// XGT 전용 프로토콜 (포트 2004)
 10→///
 11→/// 헤더 구조 (20바이트):
 12→/// [0-9]   CompanyID: "LSIS-XGT\0\0"
 13→/// [10-11] PLC Info
 14→/// [12]    CPU Info (0xA0 = XGI/XGR/XEC)
 15→/// [13]    Source of Frame (0x33=요청, 0x11=응답)
 16→/// [14-15] Invoke ID
 17→/// [16-17] Data Length (바이트 20 이후 길이, cmd+dtype 포함)
 18→/// [18]    Slot/Position
 19→/// [19]    BCC
 20→///
 21→/// 애플리케이션 명령 (20바이트~):
 22→/// [20-21] Command (0x0054=RSS읽기, 0x0058=WSS쓰기)
 23→/// [22-23] Data Type (0x0014=WORD)
 24→/// [24+]   데이터 프레임
 25→/// </summary>
 26→public static class XgtProtocol
 27→{
 28→    // CompanyID (10바이트)
 29→    private static readonly byte[] COMPANY_ID =
 30→        [0x4C, 0x53, 0x49, 0x53, 0x2D, 0x58, 0x47, 0x54, 0x00, 0x00]; // "LSIS-XGT\0\0"
 31→
 32→    private const byte CPU_INFO = 0xA0;        // XGI/XGR/XEC
 33→    private const byte SOURCE_REQUEST = 0x33;   // PC → PLC
 34→    private const byte SOURCE_RESPONSE = 0x11;  // PLC → PC
 35→
 36→    // 명령어
 37→    private const ushort CMD_RSS_REQ = 0x0054;  // 연속 읽기 요청
 38→    private const ushort CMD_RSS_RSP = 0x0055;  // 연속 읽기 응답
 39→    private const ushort CMD_WSS_REQ = 0x0058;  // 연속 쓰기 요청
 40→    private const ushort CMD_WSS_RSP = 0x0059;  // 연속 쓰기 응답
 41→
 42→    // 데이터 타입
 43→    private const ushort DATA_TYPE_WORD = 0x0014;
 44→
 45→    // 헤더 크기
 46→    private const int HEADER_SIZE = 20;
 47→    // 앱 명령 오프셋 (cmd + dtype)
 48→    private const int APP_CMD_SIZE = 4; // cmd(2) + dtype(2)
 49→
 50→    /// <summary>
 51→    /// 연속 WORD 읽기 요청 패킷 (RSS)
 52→    /// </summary>
 53→    public static byte[] BuildReadRequest(string startAddress, ushort wordCount)
 54→    {
 55→        var addrBytes = Encoding.ASCII.GetBytes(startAddress);
 56→        var addrLen = (ushort)addrBytes.Length;
 57→
 58→        // 데이터 프레임: 블록수(2) + 주소길이(2) + 주소(N) + 읽기개수(2)
 59→        var dataFrameLen = 2 + 2 + addrLen + 2;
 60→
 61→        return BuildPacket(CMD_RSS_REQ, dataFrameLen, writer =>
 62→        {
 63→            writer.Write((ushort)1);    // 블록 수
 64→            writer.Write(addrLen);      // 주소 문자열 길이
 65→            writer.Write(addrBytes);    // 주소 문자열
 66→            writer.Write(wordCount);    // 읽을 WORD 수
 67→        });
 68→    }
 69→
 70→    /// <summary>
 71→    /// 연속 WORD 쓰기 요청 패킷 (WSS)
 72→    /// </summary>
 73→    public static byte[] BuildWriteRequest(string startAddress, ushort[] values)
 74→    {
 75→        var addrBytes = Encoding.ASCII.GetBytes(startAddress);
 76→        var addrLen = (ushort)addrBytes.Length;
 77→        var wordCount = (ushort)values.Length;
 78→
 79→        // 데이터 프레임: 블록수(2) + 주소길이(2) + 주소(N) + WORD수(2) + 데이터(N*2)
 80→        var dataFrameLen = 2 + 2 + addrLen + 2 + wordCount * 2;
 81→
 82→        return BuildPacket(CMD_WSS_REQ, dataFrameLen, writer =>
 83→        {
 84→            writer.Write((ushort)1);    // 블록 수
 85→            writer.Write(addrLen);      // 주소 문자열 길이
 86→            writer.Write(addrBytes);    // 주소 문자열
 87→            writer.Write(wordCount);    // WORD 수
 88→            foreach (var val in values)
 89→                writer.Write(val);
 90→        });
 91→    }
 92→
 93→    /// <summary>
 94→    /// 응답 패킷 파싱 결과
 95→    /// </summary>
 96→    public record ParseResult(
 97→        bool Success,
 98→        ushort Command,
 99→        ushort DataType,
100→        ushort[]? Words,
101→        string ErrorInfo);
102→
103→    /// <summary>
104→    /// 응답 패킷 파싱 (범용 — 읽기/쓰기 모두)
105→    /// </summary>
106→    public static ParseResult ParseResponse(byte[] response, int length)
107→    {
108→        // 최소 헤더(20) + cmd(2) + dtype(2) = 24바이트
109→        if (length < 24)
110→            return new(false, 0, 0, null,
111→                $"응답 너무 짧음: {length}B (최소 24B 필요)");
112→
113→        // 헤더 파싱 (20바이트 기준)
114→        var source = response[13];
115→        var dataLen = BitConverter.ToUInt16(response, 16);
116→        var command = BitConverter.ToUInt16(response, 20);
117→        var dataType = BitConverter.ToUInt16(response, 22);
118→
119→        // 방향 확인
120→        if (source != SOURCE_RESPONSE)
121→            return new(false, command, dataType, null,
122→                $"응답 Source=0x{source:X2} (0x11 예상)");
123→
124→        // cmd(2) + dtype(2) 이후 = 바이트 24부터
125→        var appDataOffset = 24;
126→        var appDataLen = length - appDataOffset;
127→
128→        if (appDataLen < 2)
129→            return new(false, command, dataType, null,
130→                $"데이터 없음: cmd=0x{command:X4}, dataLen={dataLen}, total={length}B");
131→
132→        // 읽기 응답 (0x0055)
133→        if (command == CMD_RSS_RSP)
134→            return ParseReadData(response, length, appDataOffset);
135→
136→        // 쓰기 응답 (0x0059)
137→        if (command == CMD_WSS_RSP)
138→            return ParseWriteData(response, length, appDataOffset);
139→
140→        // 알 수 없는 명령
141→        return new(false, command, dataType, null,
142→            $"미지원 응답 cmd=0x{command:X4}");
143→    }
144→
145→    private static ParseResult ParseReadData(byte[] response, int length, int offset)
146→    {
147→        // [offset+0,1] = 블록 수
