using System;
using System.Windows;
using System.Windows.Threading;
using AssembleMonitor.Features.Communication;

namespace AssembleMonitor.Features.ServoTest;

/// <summary>
/// PC에서 PLC I/O 직접 제어 — 서보 테스트
/// PLC 프로그램 없이 XGT FEnet으로 %QW/%IW/%UW 직접 접근
/// </summary>
public partial class ServoTestWindow : Window
{
    private readonly XgtClient _client = new();
    private readonly DispatcherTimer _pollTimer;

    public ServoTestWindow()
    {
        InitializeComponent();
        _client.OnLog = Log;

        _pollTimer = new DispatcherTimer { Interval = TimeSpan.FromMilliseconds(200) };
        _pollTimer.Tick += PollTimer_Tick;
    }

    private void Log(string msg)
    {
        Dispatcher.BeginInvoke(() =>
        {
            tbLog.AppendText(msg + "\n");
            if (tbLog.Text.Length > 5000)
                tbLog.Text = tbLog.Text[^3000..];
            tbLog.ScrollToEnd();
        });
    }

    // === 연결 ===
    private async void BtnConnect_Click(object sender, RoutedEventArgs e)
    {
        if (_client.IsConnected)
        {
            _pollTimer.Stop();
            _client.Disconnect();
            tbStatus.Text = "미연결";
            tbStatus.Foreground = new System.Windows.Media.SolidColorBrush(
                System.Windows.Media.Color.FromRgb(0xFF, 0x45, 0x00));
            btnConnect.Content = "연결";
            return;
        }

        _client.IpAddress = tbIp.Text.Trim();
        tbStatus.Text = "연결 중...";

        if (await _client.ConnectAsync())
        {
            tbStatus.Text = "연결됨";
            tbStatus.Foreground = new System.Windows.Media.SolidColorBrush(
                System.Windows.Media.Color.FromRgb(0x00, 0xFF, 0x00));
            btnConnect.Content = "끊기";
            _pollTimer.Start();
        }
        else
        {
            tbStatus.Text = "실패";
        }
    }

    // === 서보 MC ON/OFF ===
    private async void BtnServoOn_Click(object sender, RoutedEventArgs e)
    {
        await SetOutputBit(0, 5, true);
        tbServoState.Text = "ON";
        tbServoState.Foreground = new System.Windows.Media.SolidColorBrush(
            System.Windows.Media.Color.FromRgb(0x00, 0xFF, 0x00));
    }

    private async void BtnServoOff_Click(object sender, RoutedEventArgs e)
    {
        await SetOutputBit(0, 5, false);
        tbServoState.Text = "OFF";
        tbServoState.Foreground = new System.Windows.Media.SolidColorBrush(
            System.Windows.Media.Color.FromRgb(0xFF, 0x45, 0x00));
    }

    // === JOG (누르는 동안 ON, 떼면 OFF) ===
    private async void BtnJogCW_Down(object sender, System.Windows.Input.MouseButtonEventArgs e)
    {
        await SetUBit(9, 16, true);  // %UX0.9.16 = JOG CW
    }

    private async void BtnJogCW_Up(object sender, System.Windows.Input.MouseButtonEventArgs e)
    {
        await SetUBit(9, 16, false);
    }

    private async void BtnJogCCW_Down(object sender, System.Windows.Input.MouseButtonEventArgs e)
    {
        await SetUBit(9, 17, true);  // %UX0.9.17 = JOG CCW
    }

    private async void BtnJogCCW_Up(object sender, System.Windows.Input.MouseButtonEventArgs e)
    {
        await SetUBit(9, 17, false);
    }

    // === 폴링 — 입력/상태 읽기 ===
    private async void PollTimer_Tick(object? sender, EventArgs e)
    {
        if (!_client.IsConnected) return;

        try
        {
            // 입력 읽기: %IW0.0.0 (슬롯0 입력 워드0, 비트 0~15)
            var inputWords = await _client.ReadWordsAsync("%IW0.0.0", 1);
            if (inputWords != null && inputWords.Length > 0)
            {
                var w = inputWords[0];
                UpdateBit(tbIn00, "IN00", w, 0);
                UpdateBit(tbIn01, "IN01", w, 1);
                UpdateBit(tbIn05, "IN05", w, 5);
                UpdateBit(tbIn11, "IN11", w, 11);
                UpdateBit(tbIn13, "IN13", w, 13);
                UpdateBit(tbIn15, "IN15", w, 15);
            }

            // 출력 읽기: %QW0.0.0 (서보MC 상태)
            var outWords = await _client.ReadWordsAsync("%QW0.0.0", 1);
            if (outWords != null && outWords.Length > 0)
            {
                var servoOn = (outWords[0] & (1 << 5)) != 0;
                tbServoState.Text = servoOn ? "ON" : "OFF";
                tbServoState.Foreground = new System.Windows.Media.SolidColorBrush(
                    servoOn
                        ? System.Windows.Media.Color.FromRgb(0x00, 0xFF, 0x00)
                        : System.Windows.Media.Color.FromRgb(0xFF, 0x45, 0x00));
            }

            // U영역 읽기: %UW0.9.0 (2워드 — RDY + JOG)
            var uWords = await _client.ReadWordsAsync("%UW0.9.0", 2);
            if (uWords != null && uWords.Length >= 2)
            {
                UpdateBit(tbRdy, "RDY", uWords[0], 15);
                UpdateBit(tbJogCW, "JCW", uWords[1], 0);
                UpdateBit(tbJogCCW, "JCCW", uWords[1], 1);
            }
        }
        catch (Exception ex)
        {
            Log($"폴링 에러: {ex.Message}");
        }
    }

    // === 유틸 — 출력 비트 ON/OFF ===
    private async System.Threading.Tasks.Task SetOutputBit(int slot, int bit, bool on)
    {
        if (!_client.IsConnected) return;

        var wordIdx = bit / 16;
        var bitIdx = bit % 16;

        // 현재 값 읽기
        var words = await _client.ReadWordsAsync($"%QW0.{slot}.{wordIdx}", 1);
        ushort current = (words != null && words.Length > 0) ? words[0] : (ushort)0;

        // 비트 세팅
        if (on)
            current |= (ushort)(1 << bitIdx);
        else
            current &= (ushort)~(1 << bitIdx);

        // 쓰기
        await _client.WriteWordsAsync($"%QW0.{slot}.{wordIdx}", [current]);
    }

    // === 유틸 — U영역 비트 ON/OFF ===
    private async System.Threading.Tasks.Task SetUBit(int slot, int bitAbsolute, bool on)
    {
        if (!_client.IsConnected) return;

        var wordIdx = bitAbsolute / 16;
        var bitIdx = bitAbsolute % 16;

        // 현재 값 읽기
        var words = await _client.ReadWordsAsync($"%UW0.{slot}.{wordIdx}", 1);
        ushort current = (words != null && words.Length > 0) ? words[0] : (ushort)0;

        // 비트 세팅
        if (on)
            current |= (ushort)(1 << bitIdx);
        else
            current &= (ushort)~(1 << bitIdx);

        // 쓰기
        await _client.WriteWordsAsync($"%UW0.{slot}.{wordIdx}", [current]);
    }

    // === 유틸 — 비트 상태 표시 ===
    private void UpdateBit(System.Windows.Controls.TextBlock tb, string label, ushort word, int bit)
    {
        var on = (word & (1 << bit)) != 0;
        tb.Text = $"{label}:{(on ? 1 : 0)}";
        tb.Foreground = new System.Windows.Media.SolidColorBrush(
            on ? System.Windows.Media.Color.FromRgb(0x00, 0xFF, 0x00)
               : System.Windows.Media.Color.FromRgb(0x88, 0x88, 0x88));
    }

    private void Window_Closed(object sender, EventArgs e)
    {
        _pollTimer.Stop();
        _client.Dispose();
    }
}

